};

scwin.udc_user_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_userId, ed_userNm, '31', 'CD');
};

scwin.udc_user_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_userId, ed_userNm, '31', 'NM');
};

scwin.udc_pic_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_picId, ed_picNm, '32', 'ALL');
};

scwin.udc_pic_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_picId, ed_picNm, '32', 'CD');
};

scwin.udc_pic_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_picId, ed_picNm, '32', 'NM');
};

scwin.udc_reg_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_regId, ed_regNm, '33', 'ALL');
};

scwin.udc_reg_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_regId, ed_regNm, '33', 'CD');
};

scwin.udc_reg_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_regId, ed_regNm, '33', 'NM');
};

scwin.gr_additionalValue_ontextimageclick = function (e) {
    scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
}

scwin.sbm_magam_submitdone = function (e) {
    ed_magamDt.setValue(e.responseJSON.GAUCE[0].col1 || "");
}
scwin.gr_additionalValue_onafteredit = function (rowIndex, columnIndex, value) {
    row = rowIndex;
    colId = gr_additionalValue.getColumnID(columnIndex);
    if (colId == "clntNo") {
        scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
    }
    if (colId == "summaryCombo") {
        gr_additionalValue.setCellReadOnly(row, "summary", true);
        if (value == "1") {
            ds_additionalValue.setCellData(row, "summary", "포함 요청");
        } else if (value == "2") {
            ds_additionalValue.setCellData(row, "summary", "포함해제 요청");
        } else if (value == "3") {
            ds_additionalValue.setCellData(row, "summary", "");
            gr_additionalValue.setCellReadOnly(row, "summary", false);
        }
    }
}

scwin.gr_additionalValue_onviewchange = function (info) {
    if (info.colId == "clntNo") {
        scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
    }
    if (info.colId == "summaryCombo") {
        row = info.rowIndex;
        gr_additionalValue.setCellReadOnly(row, "summary", true);
        if (info.newValue == "1") {
            ds_additionalValue.setCellData(row, "summary", "포함 요청");
        } else if (info.newValue == "2") {
            ds_additionalValue.setCellData(row, "summary", "포함해제 요청");
        } else if (info.newValue == "3") {
            ds_additionalValue.setCellData(row, "summary", "");
            gr_additionalValue.setCellReadOnly(row, "summary", false);
        }
    }
};

scwin.btn_includeSave_onclick = function (e) {
    scwin.f_IncludeSave();
};

scwin.gr_additionalValue_oncellclick = function (rowIndex, columnIndex, columnId) {
    debugger;
    row = rowIndex;
    colid = columnId;
    if (txt_closeYn.getValue() == "확정") {
        gr_additionalValue.setCellReadOnly(row, "clntNo", true);
        gr_additionalValue.setCellReadOnly(row, "stdDt", true);
        gr_additionalValue.setCellReadOnly(row, "amtFcrc", true);
        gr_additionalValue.setCellReadOnly(row, "summary", true);
        gr_additionalValue.setCellReadOnly(row, "summaryCombo", true);
    } else {
        if (colid == "summary") {
            var combo = ds_additionalValue.getCellData(row, "summaryCombo");
            switch (combo) {
                case "0":
                    // 	 			ds_additionalValue.NameValue(row,"summary") = "";
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
                case "1":
                    // 				ds_additionalValue.NameValue(row,"summary") = "포함 요청";
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
                case "2":
                    // 				ds_additionalValue.NameValue(row,"summary") = "포함해제 요청";
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
                case "3":
                    // 				ds_additionalValue.NameValue(row,"summary") = "";
                    gr_additionalValue.setCellReadOnly(row, "summary", false);
                    break;
                default:
                    gr_additionalValue.setCellReadOnly(row, "summary", true);
                    break;
            }
        }
        if (ds_additionalValue.getRowStatus(row) == "C") {
            gr_additionalValue.setReadOnly("grid", false);
            gr_additionalValue.setCellReadOnly(row, "clntNo", false);
            gr_additionalValue.setCellReadOnly(row, "stdDt", false);
        } else {
            gr_additionalValue.setCellReadOnly(row, "clntNo", true);
            gr_additionalValue.setCellReadOnly(row, "stdDt", false);

            if (ds_auth.getTotalRow() != 0 || ds_additionalValue.getCellData(row, "regId") == scwin.g_sUserId) {
                gr_additionalValue.setReadOnly("grid", false);
                gr_additionalValue.setCellReadOnly(row, "amtFcrc", false);
                gr_additionalValue.setCellReadOnly(row, "stdDt", false);
                gr_additionalValue.setCellReadOnly(row, "summaryCombo", false);
            } else {
                gr_additionalValue.setReadOnly("grid", true);
                gr_additionalValue.setCellReadOnly(row, "amtFcrc", true);
                gr_additionalValue.setCellReadOnly(row, "stdDt", true);
                gr_additionalValue.setCellReadOnly(row, "summaryCombo", true);
            }
        }
    }
};

scwin.gr_additionalValue_oneditend = async function (rowIndex, columnIndex, value) {
    if (gr_additionalValue.getColumnID(columnIndex) == "stdDt" && value != "") {
        var vStdDt = value.substring(0, 6);
        if (vStdDt != ed_stdYm.getValue()) {
            await $c.win.alert("날짜는 기준년월의 월과 같아야 합니다.");
            gr_additionalValue.setFocusedCell(rowIndex, "stdDt", true);
            return false;
        }

        var cnt = 0;

        for (var j = 0; j < ds_paymentDt.getTotalRow(); j++) {
            if (value == ds_paymentDt.getCellData(j, "paymentDt")) {
                cnt++;
            }
        }

        if (cnt == 0) {
            await $c.win.alert("날짜가 자금 집행일이 아닙니다.자금 집행일과 같은 날짜로 입력하세요");
            gr_additionalValue.setFocusedCell(rowIndex, "stdDt", true);
            return false;
        }
    }
};
